8748	    /**
8749	     * @param {Object} output The output of the model.
8750	     * @param {Tensor} output.logits The output logits of the model.
8751	     * @param {Tensor} output.past_key_values An tensor of key/value pairs that represent the previous state of the model.
8752	     * @param {Tensor} output.encoder_outputs The output of the encoder in a sequence-to-sequence model.
8753	     * @param {Tensor} [output.decoder_attentions] Attentions weights of the decoder, after the attention softmax, used to compute the weighted average in the self-attention heads.
8754	     * @param {Tensor} [output.cross_attentions] Attentions weights of the decoder's cross-attention layer, after the attention softmax, used to compute the weighted average in the cross-attention heads.
8755	     */
8756	    constructor({ logits, past_key_values, encoder_outputs, decoder_attentions = null, cross_attentions = null }) {
8757	        super();
8758	        this.logits = logits;
8759	        this.past_key_values = past_key_values;
8760	        this.encoder_outputs = encoder_outputs;
8761	        this.decoder_attentions = decoder_attentions;
8762	        this.cross_attentions = cross_attentions;
