export class RawImage {
    constructor(data, width, height, channels) {
        this.data = data;           // Uint8ClampedArray
        this.width = width;
        this.height = height;
        this.channels = channels;   // 1, 2, 3, or 4
    }

    get size() {
        return [this.width, this.height];
    }

    // Universal image loader
    static async read(input) {
        if (input instanceof RawImage) {
            return input;
        } else if (typeof input === 'string' || input instanceof URL) {
            return await this.fromURL(input);
        } else if (input instanceof Blob) {
            return await this.fromBlob(input);
        } else if (input instanceof HTMLCanvasElement || OffscreenCanvas) {
            return this.fromCanvas(input);
        } else {
            throw new Error(`Unsupported input type: ${typeof input}`);
        }
    }

    // Additional methods: fromURL(), fromBlob(), fromCanvas()
    // Supports environment-specific loading (Node.js with sharp, Browser with createImageBitmap)
}
